qry:select.qry:xquery:
	for $r in SQL('

SELECT 
PER01_PERSONAL.d_ape_y_nom,
PER02_POSIC_PER.f_ingreso as f_ingreso,
PER02_POSIC_PER.f_egreso,
PER05_MOT_CAMBIO.d_motivo_cambio

FROM
PER02_PERSONAL_EMP,
PER02_POSIC_PER,
PER01_PERSONAL,
PER05_MOT_CAMBIO

JOIN
PER02_PERSONAL_EMP.oi_personal_emp INNER PER02_POSIC_PER.oi_personal_emp, 
PER02_PERSONAL_EMP.oi_personal INNER PER01_PERSONAL.oi_personal, 
PER02_POSIC_PER.oi_motivo_cambio LEFT PER05_MOT_CAMBIO.oi_motivo_cambio

WHERE
1=1
{%?($FILTER/@oi_empresa!='')
	{% AND PER02_PERSONAL_EMP.oi_empresa = {$FILTER/@oi_empresa} %}
	{%%}
%}
{%?($FILTER/@oi_posicion!='')
	{% AND PER02_POSIC_PER.oi_posicion = {$FILTER/@oi_posicion} %}
	{%%}
%}
{%?($FILTER/@f_desde!='')
	{% AND PER02_POSIC_PER.f_ingreso >= {$FILTER/@f_desde} %}
	{%%}
%}
{%?($FILTER/@f_hasta!='')
	{% AND PER02_POSIC_PER.f_ingreso <= {$FILTER/@f_hasta} %}
	{%%}
%}

ORDER BY
f_ingreso ASC

')/ROWS/ROW
